insert into public.categories (slug, name, description) values
  ('yoga', 'Yoga', 'Instructional content teaching individual yoga asanas, breathwork, and short follow-along technique sequences. Scoped to pose mechanics and alignment, not generic fitness or aesthetics.'),
  ('running', 'Running', 'Instructional content on running technique, form drills, and biomechanics for road and trail runners. Scoped to teachable technique, not race vlogs or highlight reels.'),
  ('pilates', 'Pilates', 'Instructional mat and reformer Pilates teaching specific exercises and their form. Scoped to teachable movements and technique, distinct from general gym strength training.'),
  ('swimming', 'Swimming', 'Instructional content teaching swim-stroke technique and drills across freestyle, backstroke, breaststroke, and butterfly. Scoped to teachable micro-skills, not race footage.'),
  ('cycling', 'Cycling', 'Instructional content on road-cycling bike-handling skills, technique, and maintenance how-tos. Scoped to teachable skills, not race coverage or vlogs.'),
  ('soccer', 'Soccer (Individual Skills)', 'Instructional content teaching INDIVIDUAL football technique only: ball mastery, dribbling, first touch, passing, finishing, 1v1 moves, free kicks, and weak-foot. Excludes team tactics, formations, and team coaching.'),
